import React, { useState, useEffect } from 'react';
import { supabase } from './supabase';
import Header from './Header';

function EditProfilePage() {
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [profile, setProfile] = useState({
    name: '',
    email: '',
    phone: '',
    bio: '',
    country: 'Thailand',
    city: '',
    category: '',
    subcategory: '',
    job: '',
    price: '',
    tags: [],
    languages: [],
    available: true,
    image_url: ''
  });
  const [tagInput, setTagInput] = useState('');
  const [languageInput, setLanguageInput] = useState('');

  const COUNTRIES = ['Thailand'];
  const CITIES = ['Koh Samui', 'Koh Phangan', 'Don Sak', 'Koh Tao', 'Phuket', 'Bangkok', 'Chiang Mai', 'Krabi', 'Pattaya', 'Hua Hin'];
  const CATEGORIES = [
    'Massage & Wellness',
    'Tours & Adventures',
    'Yoga & Fitness',
    'Cooking Classes',
    'Diving & Water Sports',
    'Photography'
  ];

  const SUBCATEGORIES = {
    'Massage & Wellness': ['Thai Massage', 'Sports Massage', 'Hot Stone Massage', 'Reflexology', 'Couple Massage', 'Herbal Compress'],
    'Tours & Adventures': ['Island Tours', 'Yacht Tours', 'Fishing Charters', 'Horseback Riding', 'Mountain Biking', 'Cave Exploration', 'Island Hopping', 'Elephant Sanctuary', 'Mountain Hiking'],
    'Yoga & Fitness': ['Hatha Yoga', 'SUP Yoga', 'Muay Thai', 'Golf', 'Pilates', 'Prenatal Yoga', 'Meditation', 'Aerial Yoga', 'Thai Boxing', 'CrossFit', 'Pole Fitness'],
    'Cooking Classes': ['Thai Cuisine', 'Vegan Cuisine', 'Street Food', 'Seafood', 'River Cooking', 'Yacht Cuisine', 'Fruit Carving'],
    'Diving & Water Sports': ['Scuba Diving', 'Kitesurfing', 'Freediving', 'Snorkeling', 'Wreck Diving', 'Windsurfing'],
    'Photography': ['Wedding Photography', 'Landscape Photography', 'Underwater Photography', 'Street Photography', 'Sunset Photography', 'Boudoir Photography', 'Wildlife Photography', 'Temple Photography']
  };

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) {
        window.location.href = '/';
        return;
      }

      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('user_id', user.id)
        .single();

      if (error) throw error;

      if (data) {
        setProfile({
          name: data.name || '',
          email: data.email || '',
          phone: data.phone || '',
          bio: data.bio || '',
          country: data.country || 'Thailand',
          city: data.city || '',
          category: data.category || '',
          subcategory: data.subcategory || '',
          job: data.job || '',
          price: data.price || '',
          tags: data.tags || [],
          languages: data.languages || [],
          available: data.available !== false,
          image_url: data.image_url || ''
        });
      }
    } catch (error) {
      console.error('Error fetching profile:', error);
      alert('Error loading profile');
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);

    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error('Not authenticated');

      const { error } = await supabase
        .from('profiles')
        .update({
          name: profile.name,
          phone: profile.phone,
          bio: profile.bio,
          country: profile.country,
          city: profile.city,
          category: profile.category,
          subcategory: profile.subcategory,
          job: profile.job,
          price: profile.price,
          tags: profile.tags,
          languages: profile.languages,
          available: profile.available,
          image_url: profile.image_url
        })
        .eq('user_id', user.id);

      if (error) throw error;

      alert('Profile updated successfully!');
      window.navigateTo('dashboard');
    } catch (error) {
      console.error('Error updating profile:', error);
      alert('Error updating profile: ' + error.message);
    } finally {
      setSaving(false);
    }
  };

  const addTag = () => {
    if (tagInput.trim() && !profile.tags.includes(tagInput.trim())) {
      setProfile({ ...profile, tags: [...profile.tags, tagInput.trim()] });
      setTagInput('');
    }
  };

  const removeTag = (tag) => {
    setProfile({ ...profile, tags: profile.tags.filter(t => t !== tag) });
  };

  const addLanguage = () => {
    if (languageInput.trim() && !profile.languages.includes(languageInput.trim())) {
      setProfile({ ...profile, languages: [...profile.languages, languageInput.trim()] });
      setLanguageInput('');
    }
  };

  const removeLanguage = (lang) => {
    setProfile({ ...profile, languages: profile.languages.filter(l => l !== lang) });
  };

  if (loading) {
    return <div style={styles.loading}>Loading...</div>;
  }

  return (
    <div style={styles.page}>
      <link href="https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700;800&display=swap" rel="stylesheet" />
      <Header />
      <div style={styles.container}>
        <h1 style={styles.title}>Edit Profile</h1>

        <form onSubmit={handleSubmit} style={styles.form}>
          <div style={styles.section}>
            <h3 style={styles.sectionTitle}>Basic Information</h3>

            <label style={styles.label}>Name *</label>
            <input
              type="text"
              value={profile.name}
              onChange={(e) => setProfile({ ...profile, name: e.target.value })}
              style={styles.input}
              required
            />

            <label style={styles.label}>Email (read-only)</label>
            <input
              type="email"
              value={profile.email}
              style={{ ...styles.input, background: '#f3f4f6', cursor: 'not-allowed' }}
              disabled
            />

            <label style={styles.label}>Phone</label>
            <input
              type="tel"
              value={profile.phone}
              onChange={(e) => setProfile({ ...profile, phone: e.target.value })}
              style={styles.input}
              placeholder="+66 123 456 789"
            />

            <label style={styles.label}>Profile Photo (Emoji or URL)</label>
            <input
              type="text"
              value={profile.image_url}
              onChange={(e) => setProfile({ ...profile, image_url: e.target.value })}
              style={styles.input}
              placeholder="🧘‍♀️ or https://..."
            />

            <label style={styles.label}>Bio</label>
            <textarea
              value={profile.bio}
              onChange={(e) => setProfile({ ...profile, bio: e.target.value })}
              style={styles.textarea}
              rows={4}
              placeholder="Tell people about yourself and your services..."
            />
          </div>

          <div style={styles.section}>
            <h3 style={styles.sectionTitle}>Location</h3>

            <label style={styles.label}>Country *</label>
            <select
              value={profile.country}
              onChange={(e) => setProfile({ ...profile, country: e.target.value })}
              style={styles.input}
              required
            >
              {COUNTRIES.map(c => (
                <option key={c} value={c}>{c}</option>
              ))}
            </select>

            <label style={styles.label}>City *</label>
            <select
              value={profile.city}
              onChange={(e) => setProfile({ ...profile, city: e.target.value })}
              style={styles.input}
              required
            >
              <option value="">Select city</option>
              {CITIES.map(c => (
                <option key={c} value={c}>{c}</option>
              ))}
            </select>
          </div>

          <div style={styles.section}>
            <h3 style={styles.sectionTitle}>Service Details</h3>

            <label style={styles.label}>Category *</label>
            <select
              value={profile.category}
              onChange={(e) => {
                setProfile({ ...profile, category: e.target.value, subcategory: '' });
              }}
              style={styles.input}
              required
            >
              <option value="">Select category</option>
              {CATEGORIES.map(c => (
                <option key={c} value={c}>{c}</option>
              ))}
            </select>

            {profile.category && (
              <>
                <label style={styles.label}>Subcategory *</label>
                <select
                  value={profile.subcategory}
                  onChange={(e) => setProfile({ ...profile, subcategory: e.target.value })}
                  style={styles.input}
                  required
                >
                  <option value="">Select subcategory</option>
                  {SUBCATEGORIES[profile.category]?.map(sc => (
                    <option key={sc} value={sc}>{sc}</option>
                  ))}
                </select>
              </>
            )}

            <label style={styles.label}>Job Title</label>
            <input
              type="text"
              value={profile.job}
              onChange={(e) => setProfile({ ...profile, job: e.target.value })}
              style={styles.input}
              placeholder="e.g., Certified Massage Therapist"
            />

            <label style={styles.label}>Price</label>
            <input
              type="text"
              value={profile.price}
              onChange={(e) => setProfile({ ...profile, price: e.target.value })}
              style={styles.input}
              placeholder="e.g., ฿800/hour"
            />
          </div>

          <div style={styles.section}>
            <h3 style={styles.sectionTitle}>Skills & Languages</h3>

            <label style={styles.label}>Skills/Tags</label>
            <div style={{ display: 'flex', gap: 8, marginBottom: 8 }}>
              <input
                type="text"
                value={tagInput}
                onChange={(e) => setTagInput(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), addTag())}
                style={{ ...styles.input, flex: 1 }}
                placeholder="Add a skill (e.g., Deep Tissue)"
              />
              <button type="button" onClick={addTag} style={styles.addBtn}>Add</button>
            </div>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
              {profile.tags.map(tag => (
                <span key={tag} style={styles.tag}>
                  {tag}
                  <button type="button" onClick={() => removeTag(tag)} style={styles.tagRemove}>×</button>
                </span>
              ))}
            </div>

            <label style={styles.label} style={{ marginTop: 16 }}>Languages</label>
            <div style={{ display: 'flex', gap: 8, marginBottom: 8 }}>
              <input
                type="text"
                value={languageInput}
                onChange={(e) => setLanguageInput(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), addLanguage())}
                style={{ ...styles.input, flex: 1 }}
                placeholder="Add a language (e.g., English)"
              />
              <button type="button" onClick={addLanguage} style={styles.addBtn}>Add</button>
            </div>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
              {profile.languages.map(lang => (
                <span key={lang} style={styles.tag}>
                  {lang}
                  <button type="button" onClick={() => removeLanguage(lang)} style={styles.tagRemove}>×</button>
                </span>
              ))}
            </div>
          </div>

          <div style={styles.section}>
            <h3 style={styles.sectionTitle}>Availability</h3>
            <label style={{ display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer' }}>
              <input
                type="checkbox"
                checked={profile.available}
                onChange={(e) => setProfile({ ...profile, available: e.target.checked })}
              />
              <span>Currently available for bookings</span>
            </label>
          </div>

          <div style={{ display: 'flex', gap: 12, marginTop: 24 }}>
            <button type="submit" disabled={saving} style={styles.submitBtn}>
              {saving ? 'Saving...' : 'Save Changes'}
            </button>
            <button 
              type="button" 
              onClick={() => window.navigateTo('dashboard')} 
              style={styles.cancelBtn}
            >
              Cancel
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

const styles = {
  page: { fontFamily: '"Outfit", sans-serif', background: '#f9fafb', minHeight: '100vh', paddingTop: 80 },
  loading: { minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 18 },
  container: { maxWidth: 800, margin: '0 auto', padding: '40px 20px' },
  title: { fontSize: 32, fontWeight: 800, marginBottom: 32, color: '#111827' },
  form: { background: '#fff', borderRadius: 16, padding: 32, boxShadow: '0 2px 8px rgba(0,0,0,0.08)' },
  section: { marginBottom: 32, paddingBottom: 32, borderBottom: '1px solid #e5e7eb' },
  sectionTitle: { fontSize: 18, fontWeight: 700, marginBottom: 16, color: '#374151' },
  label: { display: 'block', fontSize: 14, fontWeight: 600, color: '#374151', marginBottom: 6, marginTop: 16 },
  input: { width: '100%', padding: '10px 12px', fontSize: 15, border: '1.5px solid #e5e7eb', borderRadius: 8, outline: 'none', fontFamily: '"Outfit", sans-serif' },
  textarea: { width: '100%', padding: '10px 12px', fontSize: 15, border: '1.5px solid #e5e7eb', borderRadius: 8, outline: 'none', fontFamily: '"Outfit", sans-serif', resize: 'vertical' },
  addBtn: { padding: '10px 20px', background: '#065f46', color: '#fff', border: 'none', borderRadius: 8, fontSize: 14, fontWeight: 600, cursor: 'pointer', fontFamily: '"Outfit", sans-serif' },
  tag: { background: '#ecfdf5', color: '#065f46', padding: '6px 12px', borderRadius: 16, fontSize: 13, fontWeight: 500, display: 'inline-flex', alignItems: 'center', gap: 6 },
  tagRemove: { background: 'none', border: 'none', color: '#065f46', cursor: 'pointer', fontSize: 16, fontWeight: 700, padding: 0 },
  submitBtn: { flex: 1, padding: '14px', background: 'linear-gradient(135deg, #065f46 0%, #047857 100%)', color: '#fff', border: 'none', borderRadius: 12, fontSize: 16, fontWeight: 700, cursor: 'pointer', fontFamily: '"Outfit", sans-serif' },
  cancelBtn: { flex: 1, padding: '14px', background: '#fff', color: '#6b7280', border: '1.5px solid #e5e7eb', borderRadius: 12, fontSize: 16, fontWeight: 600, cursor: 'pointer', fontFamily: '"Outfit", sans-serif' }
};

export default EditProfilePage;
